function r(e){return new Intl.NumberFormat("en-US",{style:"currency",currency:"USD"}).format(e)}function n(e){return new Date(e).toLocaleDateString("en-US",{year:"numeric",month:"short",day:"numeric",hour:"2-digit",minute:"2-digit"})}function g(e,t=100){return!e||e.length<=t?e:e.slice(0,t)+"..."}function o(e){return{placed:"bg-blue-100 text-blue-800",confirmed:"bg-indigo-100 text-indigo-800",packed:"bg-purple-100 text-purple-800",shipped:"bg-yellow-100 text-yellow-800",out_for_delivery:"bg-orange-100 text-orange-800",delivered:"bg-green-100 text-green-800",cancelled:"bg-red-100 text-red-800",active:"bg-green-100 text-green-800",inactive:"bg-gray-100 text-gray-800",pending:"bg-yellow-100 text-yellow-800",approved:"bg-green-100 text-green-800",rejected:"bg-red-100 text-red-800",disabled:"bg-gray-100 text-gray-800"}[e]||"bg-gray-100 text-gray-800"}export{n as a,r as f,o as g,g as t};
